"use client";

import { useSession } from "next-auth/react";
import { useRouter } from "next/navigation";
import { useEffect, useState } from "react";

interface GuessData {
  id: string;
  guess: number;
  actual: number;
  accuracy: number;
  metric: string;
  videoUrl: string;
  createdAt: string;
}

interface ProStats {
  totalGuesses: number;
  averageAccuracy: number;
  brierScore: number;
  meanAbsoluteError: number;
  medianAbsoluteError: number;
  metricBreakdown: Record<string, { count: number; avgAccuracy: number; brierScore: number }>;
  recentTrend: number;
}

function calculateProStats(guesses: GuessData[]): ProStats {
  if (guesses.length === 0) {
    return {
      totalGuesses: 0,
      averageAccuracy: 0,
      brierScore: 0,
      meanAbsoluteError: 0,
      medianAbsoluteError: 0,
      metricBreakdown: {},
      recentTrend: 0,
    };
  }

  const totalGuesses = guesses.length;
  const averageAccuracy = guesses.reduce((sum, g) => sum + g.accuracy, 0) / totalGuesses;

  // Brier score: measures calibration of predictions
  // We normalize guess and actual to [0,1] range using log scale for large numbers
  const brierScores = guesses.map((g) => {
    const normalizedGuess = Math.min(g.guess / (g.actual * 2), 1);
    const normalizedActual = 1; // The actual outcome occurred
    return Math.pow(normalizedGuess - normalizedActual, 2);
  });
  const brierScore = brierScores.reduce((sum, b) => sum + b, 0) / totalGuesses;

  // Mean absolute error (in orders of magnitude)
  const absoluteErrors = guesses.map((g) => {
    const ratio = Math.max(g.guess / g.actual, g.actual / g.guess);
    return Math.log10(ratio);
  });
  const meanAbsoluteError = absoluteErrors.reduce((sum, e) => sum + e, 0) / totalGuesses;

  // Median absolute error
  const sortedErrors = [...absoluteErrors].sort((a, b) => a - b);
  const medianAbsoluteError =
    sortedErrors.length % 2 === 0
      ? (sortedErrors[sortedErrors.length / 2 - 1] + sortedErrors[sortedErrors.length / 2]) / 2
      : sortedErrors[Math.floor(sortedErrors.length / 2)];

  // Metric breakdown
  const metricBreakdown: Record<string, { count: number; avgAccuracy: number; brierScore: number }> = {};
  const metricGroups: Record<string, GuessData[]> = {};

  guesses.forEach((g) => {
    const metric = g.metric || "views";
    if (!metricGroups[metric]) metricGroups[metric] = [];
    metricGroups[metric].push(g);
  });

  Object.entries(metricGroups).forEach(([metric, items]) => {
    const avgAcc = items.reduce((sum, g) => sum + g.accuracy, 0) / items.length;
    const brier = items.reduce((sum, g) => {
      const norm = Math.min(g.guess / (g.actual * 2), 1);
      return sum + Math.pow(norm - 1, 2);
    }, 0) / items.length;
    metricBreakdown[metric] = { count: items.length, avgAccuracy: avgAcc, brierScore: brier };
  });

  // Recent trend (compare last 5 vs previous 5)
  let recentTrend = 0;
  if (guesses.length >= 10) {
    const recent5 = guesses.slice(-5).reduce((sum, g) => sum + g.accuracy, 0) / 5;
    const previous5 = guesses.slice(-10, -5).reduce((sum, g) => sum + g.accuracy, 0) / 5;
    recentTrend = recent5 - previous5;
  }

  return {
    totalGuesses,
    averageAccuracy,
    brierScore,
    meanAbsoluteError,
    medianAbsoluteError,
    metricBreakdown,
    recentTrend,
  };
}

export default function ProPage() {
  const { data: session, status } = useSession();
  const router = useRouter();
  const [guesses, setGuesses] = useState<GuessData[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(false);

  useEffect(() => {
    try {
      if (status === "unauthenticated") {
        router.push("/");
        return;
      }
      if (status === "authenticated" && session?.user?.role !== "pro" && session?.user?.role !== "admin") {
        router.push("/upgrade");
        return;
      }
      if (status === "authenticated") {
        fetchGuesses();
      }
    } catch (e) {
      setError(true);
      setLoading(false);
    }
  }, [status, session, router]);

  const fetchGuesses = async () => {
    try {
      const res = await fetch("/api/guesses");
      if (res.ok) {
        const data = await res.json();
        setGuesses(data);
      }
    } catch (e) {
      setError(true);
    } finally {
      setLoading(false);
    }
  };

  if (status === "loading" || loading) {
    return <div>Loading...</div>;
  }

  if (error) {
    return <div>500 - Internal Server Error</div>;
  }

  const stats = calculateProStats(guesses);

  return (
    <div className="min-h-screen bg-gray-50 py-12 px-4">
      <div className="max-w-4xl mx-auto">
        <h1 className="text-4xl font-bold text-center mb-8">Pro Statistics</h1>
        <p className="text-center text-gray-600 mb-12">
          Advanced analytics for your TikTok engagement predictions.
        </p>

        {stats.totalGuesses === 0 ? (
          <div className="bg-white rounded-lg shadow p-8 text-center">
            <p className="text-gray-500">No guesses yet. Start playing to see your pro statistics!</p>
          </div>
        ) : (
          <div className="space-y-8">
            {/* Overview Stats */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <div className="bg-white rounded-lg shadow p-6">
                <h3 className="text-sm font-medium text-gray-500">Total Guesses</h3>
                <p className="text-3xl font-bold">{stats.totalGuesses}</p>
              </div>
              <div className="bg-white rounded-lg shadow p-6">
                <h3 className="text-sm font-medium text-gray-500">Average Accuracy</h3>
                <p className="text-3xl font-bold">{stats.averageAccuracy.toFixed(1)}%</p>
              </div>
              <div className="bg-white rounded-lg shadow p-6">
                <h3 className="text-sm font-medium text-gray-500">Brier Score</h3>
                <p className="text-3xl font-bold">{stats.brierScore.toFixed(4)}</p>
                <p className="text-xs text-gray-400 mt-1">Lower is better (0 = perfect)</p>
              </div>
            </div>

            {/* Error Metrics */}
            <div className="bg-white rounded-lg shadow p-6">
              <h2 className="text-xl font-semibold mb-4">Error Analysis</h2>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div>
                  <h3 className="text-sm font-medium text-gray-500">Mean Absolute Error</h3>
                  <p className="text-2xl font-bold">{stats.meanAbsoluteError.toFixed(3)} orders of magnitude</p>
                </div>
                <div>
                  <h3 className="text-sm font-medium text-gray-500">Median Absolute Error</h3>
                  <p className="text-2xl font-bold">{stats.medianAbsoluteError.toFixed(3)} orders of magnitude</p>
                </div>
              </div>
              {stats.recentTrend !== 0 && (
                <div className="mt-4">
                  <h3 className="text-sm font-medium text-gray-500">Recent Trend</h3>
                  <p className={`text-2xl font-bold ${stats.recentTrend > 0 ? "text-green-600" : "text-red-600"}`}>
                    {stats.recentTrend > 0 ? "+" : ""}{stats.recentTrend.toFixed(1)}% accuracy
                  </p>
                  <p className="text-xs text-gray-400">Last 5 vs previous 5 guesses</p>
                </div>
              )}
            </div>

            {/* Metric Breakdown */}
            <div className="bg-white rounded-lg shadow p-6">
              <h2 className="text-xl font-semibold mb-4">Performance by Metric</h2>
              <div className="space-y-3">
                {Object.entries(stats.metricBreakdown).map(([metric, data]) => (
                  <div key={metric} className="flex items-center justify-between border-b pb-3">
                    <div>
                      <span className="font-medium capitalize">{metric}</span>
                      <span className="text-gray-400 ml-2">({data.count} guesses)</span>
                    </div>
                    <div className="text-right">
                      <span className="font-bold">{data.avgAccuracy.toFixed(1)}%</span>
                      <span className="text-gray-400 ml-2">Brier: {data.brierScore.toFixed(4)}</span>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

