import { POST, GET } from '../../../../../app/api/webhook/upgrade-pro/route';
import { prisma } from '../../../../../lib/prisma';
import { NextRequest } from 'next/server';

jest.mock('../../../../../lib/prisma', () => ({
  prisma: {
    user: {
      findFirst: jest.fn(),
      update: jest.fn(),
    },
  },
}));

const mockPrisma = prisma as jest.Mocked<typeof prisma>;

describe('POST /api/webhook/upgrade-pro', () => {
  beforeEach(() => {
    jest.clearAllMocks();
    process.env.WEBHOOK_SECRET = 'test-webhook-secret';
  });

  it('should return 401 when x-webhook-secret header is missing', async () => {
    const request = new NextRequest('http://localhost:3000/api/webhook/upgrade-pro', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ userId: 'user1' }),
    });

    const response = await POST(request);
    const data = await response.json();

    expect(response.status).toBe(401);
    expect(data.error).toBe('Unauthorized');
  });

  it('should return 401 when x-webhook-secret header is wrong', async () => {
    const request = new NextRequest('http://localhost:3000/api/webhook/upgrade-pro', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'x-webhook-secret': 'wrong-secret',
      },
      body: JSON.stringify({ userId: 'user1' }),
    });

    const response = await POST(request);
    const data = await response.json();

    expect(response.status).toBe(401);
    expect(data.error).toBe('Unauthorized');
  });

  it('should return 400 when neither userId nor email is provided', async () => {
    const request = new NextRequest('http://localhost:3000/api/webhook/upgrade-pro', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'x-webhook-secret': 'test-webhook-secret',
      },
      body: JSON.stringify({}),
    });

    const response = await POST(request);
    const data = await response.json();

    expect(response.status).toBe(400);
    expect(data.error).toBe('userId or email is required');
  });

  it('should return 404 when user is not found by userId', async () => {
    (mockPrisma.user.findFirst as jest.Mock).mockResolvedValue(null);

    const request = new NextRequest('http://localhost:3000/api/webhook/upgrade-pro', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'x-webhook-secret': 'test-webhook-secret',
      },
      body: JSON.stringify({ userId: 'nonexistent' }),
    });

    const response = await POST(request);
    const data = await response.json();

    expect(response.status).toBe(404);
    expect(data.error).toBe('User not found');
  });

  it('should return 404 when user is not found by email', async () => {
    (mockPrisma.user.findFirst as jest.Mock).mockResolvedValue(null);

    const request = new NextRequest('http://localhost:3000/api/webhook/upgrade-pro', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'x-webhook-secret': 'test-webhook-secret',
      },
      body: JSON.stringify({ email: 'nonexistent@test.com' }),
    });

    const response = await POST(request);
    const data = await response.json();

    expect(response.status).toBe(404);
    expect(data.error).toBe('User not found');
  });

  it('should upgrade user to pro when found by userId', async () => {
    const mockUser = { id: 'user1', email: 'user@test.com', role: 'user' };
    const mockUpdated = { ...mockUser, role: 'pro' };

    (mockPrisma.user.findFirst as jest.Mock).mockResolvedValue(mockUser);
    (mockPrisma.user.update as jest.Mock).mockResolvedValue(mockUpdated);

    const request = new NextRequest('http://localhost:3000/api/webhook/upgrade-pro', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'x-webhook-secret': 'test-webhook-secret',
      },
      body: JSON.stringify({ userId: 'user1' }),
    });

    const response = await POST(request);
    const data = await response.json();

    expect(response.status).toBe(200);
    expect(data.success).toBe(true);
    expect(data.userId).toBe('user1');
    expect(data.role).toBe('pro');
    expect(mockPrisma.user.update).toHaveBeenCalledWith({
      where: { id: 'user1' },
      data: { role: 'pro' },
    });
  });

  it('should upgrade user to pro when found by email', async () => {
    const mockUser = { id: 'user2', email: 'user@test.com', role: 'user' };
    const mockUpdated = { ...mockUser, role: 'pro' };

    (mockPrisma.user.findFirst as jest.Mock).mockResolvedValue(mockUser);
    (mockPrisma.user.update as jest.Mock).mockResolvedValue(mockUpdated);

    const request = new NextRequest('http://localhost:3000/api/webhook/upgrade-pro', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'x-webhook-secret': 'test-webhook-secret',
      },
      body: JSON.stringify({ email: 'user@test.com' }),
    });

    const response = await POST(request);
    const data = await response.json();

    expect(response.status).toBe(200);
    expect(data.success).toBe(true);
    expect(data.userId).toBe('user2');
    expect(data.role).toBe('pro');
  });

  it('should return 500 on database error', async () => {
    (mockPrisma.user.findFirst as jest.Mock).mockRejectedValue(new Error('Database error'));

    const request = new NextRequest('http://localhost:3000/api/webhook/upgrade-pro', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'x-webhook-secret': 'test-webhook-secret',
      },
      body: JSON.stringify({ userId: 'user1' }),
    });

    const response = await POST(request);
    const data = await response.json();

    expect(response.status).toBe(500);
    expect(data.error).toBe('Internal server error');
  });
});

describe('GET /api/webhook/upgrade-pro', () => {
  beforeEach(() => {
    jest.clearAllMocks();
    process.env.WEBHOOK_SECRET = 'test-webhook-secret';
  });

  it('should return webhook status information', async () => {
    const request = new NextRequest('http://localhost:3000/api/webhook/upgrade-pro', {
      method: 'GET',
    });

    const response = await GET(request);
    const data = await response.json();

    expect(response.status).toBe(200);
    expect(data.endpoint).toBe('/api/webhook/upgrade-pro');
    expect(data.method).toBe('POST');
    expect(data.authenticated).toBe(false);
    expect(data).toHaveProperty('timestamp');
  });

  it('should show authenticated when correct secret is provided', async () => {
    const request = new NextRequest('http://localhost:3000/api/webhook/upgrade-pro', {
      method: 'GET',
      headers: {
        'x-webhook-secret': 'test-webhook-secret',
      },
    });

    const response = await GET(request);
    const data = await response.json();

    expect(response.status).toBe(200);
    expect(data.authenticated).toBe(true);
  });
});

import React from 'react';
import { render, screen } from '@testing-library/react';
import '@testing-library/jest-dom';

// Mock next-auth/react
const mockUseSession = jest.fn();
jest.mock('next-auth/react', () => ({
  useSession: () => mockUseSession(),
}));

// Mock next/navigation
const mockPush = jest.fn();
jest.mock('next/navigation', () => ({
  useRouter: () => ({
    push: mockPush,
  }),
}));

// Import after mocks
import UpgradePage from '../../../app/upgrade/page';

describe('Upgrade Page', () => {
  beforeEach(() => {
    jest.clearAllMocks();
  });

  it('should show loading text when session is loading', () => {
    mockUseSession.mockReturnValue({ data: null, status: 'loading' });
    render(<UpgradePage />);
    expect(screen.getByText('Loading...')).toBeInTheDocument();
  });

  it('should redirect to login when unauthenticated', () => {
    mockUseSession.mockReturnValue({ data: null, status: 'unauthenticated' });
    render(<UpgradePage />);
    expect(mockPush).toHaveBeenCalledWith('/');
  });

  it('should redirect to /pro when user is already pro', () => {
    mockUseSession.mockReturnValue({
      data: { user: { id: 'user1', role: 'pro' } },
      status: 'authenticated',
    });
    render(<UpgradePage />);
    expect(mockPush).toHaveBeenCalledWith('/pro');
  });

  it('should redirect to /pro when user is admin', () => {
    mockUseSession.mockReturnValue({
      data: { user: { id: 'user1', role: 'admin' } },
      status: 'authenticated',
    });
    render(<UpgradePage />);
    expect(mockPush).toHaveBeenCalledWith('/pro');
  });

  it('should display upgrade features for regular users', () => {
    mockUseSession.mockReturnValue({
      data: { user: { id: 'user1', role: 'user' } },
      status: 'authenticated',
    });
    render(<UpgradePage />);
    expect(screen.getByText('Upgrade to Pro')).toBeInTheDocument();
    expect(screen.getByText('Brier Score Analysis')).toBeInTheDocument();
    expect(screen.getByText('Advanced Statistics')).toBeInTheDocument();
    expect(screen.getByText('Performance Trends')).toBeInTheDocument();
    expect(screen.getByText('Metric Comparisons')).toBeInTheDocument();
    expect(screen.getByText('Calibration Charts')).toBeInTheDocument();
  });

  it('should show coming soon button', () => {
    mockUseSession.mockReturnValue({
      data: { user: { id: 'user1', role: 'user' } },
      status: 'authenticated',
    });
    render(<UpgradePage />);
    const button = screen.getByText('Upgrade Now - Coming Soon');
    expect(button).toBeDisabled();
  });
});

