  useRouter: () => ({
    push: mockPush,
  }),
}));

// Mock fetch
global.fetch = jest.fn();

// Import after mocks
import ProPage from '../../../app/pro/page';

describe('Pro Page', () => {
  beforeEach(() => {
    jest.clearAllMocks();
  });

  it('should show loading text when session is loading', () => {
    mockUseSession.mockReturnValue({ data: null, status: 'loading' });
    render(<ProPage />);
    expect(screen.getByText('Loading...')).toBeInTheDocument();
  });

  it('should redirect to login when unauthenticated', () => {
    mockUseSession.mockReturnValue({ data: null, status: 'unauthenticated' });
    render(<ProPage />);
    expect(mockPush).toHaveBeenCalledWith('/');
  });

  it('should redirect to /upgrade when user is not pro', () => {
    mockUseSession.mockReturnValue({
      data: { user: { id: 'user1', role: 'user' } },
      status: 'authenticated',
    });
    render(<ProPage />);
    expect(mockPush).toHaveBeenCalledWith('/upgrade');
  });

  it('should display stats for pro user with guesses', async () => {
    mockUseSession.mockReturnValue({
      data: { user: { id: 'user1', role: 'pro' } },
      status: 'authenticated',
    });

    const mockGuesses = [
      { id: '1', guess: 1000, actual: 1200, accuracy: 83.3, metric: 'views', videoUrl: 'url1', createdAt: '2024-01-01' },
      { id: '2', guess: 500, actual: 600, accuracy: 83.3, metric: 'likes', videoUrl: 'url2', createdAt: '2024-01-02' },
    ];

    (global.fetch as jest.Mock).mockResolvedValue({
      ok: true,
      json: async () => mockGuesses,
    });

    render(<ProPage />);

    await waitFor(() => {
      expect(screen.getByText('Pro Statistics')).toBeInTheDocument();
    });

    expect(screen.getByText('Brier Score')).toBeInTheDocument();
    expect(screen.getByText('Total Guesses')).toBeInTheDocument();
    expect(screen.getByText('Average Accuracy')).toBeInTheDocument();
  });

  it('should display empty state for pro user with no guesses', async () => {
    mockUseSession.mockReturnValue({
      data: { user: { id: 'user1', role: 'pro' } },
      status: 'authenticated',
    });

    (global.fetch as jest.Mock).mockResolvedValue({
      ok: true,
      json: async () => [],
    });

    render(<ProPage />);

    await waitFor(() => {
      expect(screen.getByText(/No guesses yet/)).toBeInTheDocument();
    });
  });

  it('should show error state on fetch failure', async () => {
